python3 -c "
import xml.etree.ElementTree as ET
tree = ET.parse('/work/output/artifacts/skill-bpmn-hitl-boolean-decision/VendorApprovalBpmn/VendorApprovalBpmn.bpmn')
print('XML parse: OK')
root = tree.getroot()
ns = {
  'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
  'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
  'uipath': 'http://uipath.org/schema/bpmn',
}

# Check root tag
print('Root tag:', root.tag)

# Gather all element IDs
all_ids = {elem.get('id') for elem in root.iter() if elem.get('id')}
print('Total IDs found:', len(all_ids))

# Check all sourceRef/targetRef resolve
errors = []
for sf in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}sequenceFlow'):
    src = sf.get('sourceRef')
    tgt = sf.get('targetRef')
    if src not in all_ids: errors.append(f'Unresolved sourceRef: {src}')
    if tgt not in all_ids: errors.append(f'Unresolved targetRef: {tgt}')

# Check all bpmnElement refs in diagram
for shape in root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNShape'):
    ref = shape.get('bpmnElement')
    if ref not in all_ids: errors.append(f'BPMNShape unresolved bpmnElement: {ref}')

for edge in root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNEdge'):
    ref = edge.get('bpmnElement')
    if ref not in all_ids: errors.append(f'BPMNEdge unresolved bpmnElement: {ref}')

# Check exclusive gateway: non-default outgoing flows have conditions
for gw in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}exclusiveGateway'):
    default_flow = gw.get('default')
    outgoing = [o.text for o in gw.findall('{http://www.omg.org/spec/BPMN/20100524/MODEL}outgoing')]
    for flow_id in outgoing:
        if flow_id == default_flow:
            continue
        # Find the flow
        for sf in root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}sequenceFlow'):
            if sf.get('id') == flow_id:
                cond = sf.find('{http://www.omg.org/spec/BPMN/20100524/MODEL}conditionExpression')
                if cond is None:
                    errors.append(f'Gateway {gw.get(\"id\")} non-default flow {flow_id} missing conditionExpression')

# Count diagram shapes and edges
shapes = list(root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNShape'))
edges  = list(root.iter('{http://www.omg.org/spec/BPMN/20100524/DI}BPMNEdge'))
print(f'BPMNShapes: {len(shapes)}, BPMNEdges: {len(edges)}')

# Count flow nodes that need shapes
flow_node_tags = [
  '{http://www.omg.org/spec/BPMN/20100524/MODEL}startEvent',
  '{http://www.omg.org/spec/BPMN/20100524/MODEL}endEvent',
  '{http://www.omg.org/spec/BPMN/20100524/MODEL}userTask',
  '{http://www.omg.org/spec/BPMN/20100524/MODEL}scriptTask',
  '{http://www.omg.org/spec/BPMN/20100524/MODEL}exclusiveGateway',
]
flow_nodes = [elem for elem in root.iter() if elem.tag in flow_node_tags]
seq_flows  = list(root.iter('{http://www.omg.org/spec/BPMN/20100524/MODEL}sequenceFlow'))
print(f'Flow nodes: {len(flow_nodes)}, Sequence flows: {len(seq_flows)}')

if errors:
    for e in errors: print('ERROR:', e)
else:
    print('Structural checks: PASSED')
" 2>&1
